from elasticsearch import Elasticsearch
from flask import Flask, request, jsonify

app = Flask(__name__)
es = Elasticsearch()

@app.route('/run_aggregation', methods=['POST'])
def run_aggregation():
    try:
        script_code = request.json['script']
        index_name = request.json.get('index', 'default-index')  # Specify default index if not provided

        # Execute the dynamic script with an aggregation query
        body = {
            "size": 0,
            "aggs": {
                "dynamic_script_agg": {
                    "scripted_metric": {
                        "init_script": "state.transactions = []",
                        "map_script": script_code,
                        "combine_script": "return state.transactions",
                        "reduce_script": "def sum = 0; for (s in states) { sum += s.get(0); } return sum"
                    }
                }
            }
        }

        response = es.search(index=index_name, body=body)
        return jsonify(response['aggregations']['dynamic_script_agg']), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)